        this.addLabel('Wells', gelX + gelWidth/2, gelY - 5, '#2C3E50');
        this.addLabel('Gel Matrix', gelX + gelWidth + 10, gelY + 20, '#95A5A6', 'left');
        this.addLabel('Negative\nElectrode', gelX - 50, gelY + 20, '#E74C3C', 'right');
