    this.drawArrow(width * 0.25, height * 0.47, width * 0.25, height * 0.57, '#3498DB', '', 6);

    // CO2 molecules (orange) leaving blood
    this.ctx.fillStyle = '#E67E22';
    this.ctx.fillText('CO₂', width * 0.35, height * 0.67);
